public class TestBinomialFix {
    public static void main(String[] args) {
        try {
            // Test the specific case that was failing in the buggy version
            long result = MathUtils.binomialCoefficient(48, 22);
            System.out.println("binomialCoefficient(48, 22) = " + result);
            System.out.println("Expected: 27385657281648");
            System.out.println("Match: " + (result == 27385657281648L));

            // Test another case
            long result2 = MathUtils.binomialCoefficient(66, 33);
            System.out.println("binomialCoefficient(66, 33) = " + result2);
            System.out.println("Expected: 7219428434016265740");
            System.out.println("Match: " + (result2 == 7219428434016265740L));

            // Test overflow case
            try {
                long result3 = MathUtils.binomialCoefficient(67, 34);
                System.out.println("binomialCoefficient(67, 34) = " + result3 + " (should have thrown exception)");
            } catch (ArithmeticException e) {
                System.out.println("binomialCoefficient(67, 34) correctly threw ArithmeticException: " + e.getMessage());
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

